bash_commands.command:
python3 << 'EOF'
# Verify the signal can be imported from django.db.models.signals
import ast

with open('/workspace/django/db/models/signals.py', 'r') as f:
    tree = ast.parse(f.read())

# Find all top-level assignments
signals_defined = []
for node in ast.walk(tree):
    if isinstance(node, ast.Assign):
        for target in node.targets:
            if isinstance(target, ast.Name):
                signals_defined.append(target.id)

print("Signals defined in signals.py:")
for signal in sorted(set(signals_defined)):
    if not signal.startswith('_'):
        print(f"  • {signal}")

# Verify pre_validate is in the list
if 'pre_validate' in signals_defined:
    print("\n✓ pre_validate is properly defined and exportable")
else:
    print("\n✗ pre_validate is not found in defined signals")
EOF

